sub set_origin_header {
  if (req.backend.is_origin) {
    if (req.backend == datadome) {
        # Remove all unexpected headers
        header.filter_except(bereq, "x-datadome-params", "accept-charset", "accept-language", "x-requested-with", "x-fl-productid", "x-flapi-session-id", "fastly-orig-accept-encoding", "cache-control", "connection", "pragma", "accept", "host", "origin", "server-hostname", "server-name", "x-forwarded-for", "user-agent", "referer", "content-type", "from", "true-client-ip", "via", "x-real-ip", "sec-ch-device-memory", "sec-ch-ua", "sec-ch-ua-arch", "sec-ch-ua-full-version-list", "sec-ch-ua-mobile", "sec-ch-ua-model", "sec-ch-ua-platform", "sec-fetch-dest", "sec-fetch-mode", "sec-fetch-site", "sec-fetch-user", "sec-fetch-storage-access", "signature", "signature-agent", "signature-input", "skyfire-pay-id");
        set bereq.http.x-datadome-params:key = "{{datadome_api_key}}";
        set bereq.http.x-datadome-params:requestmodulename = "FastlyMagento";
        set bereq.http.x-datadome-params:moduleversion = "2.31.0";
        set bereq.http.x-datadome-params:timerequest = time.start.usec;
        set bereq.http.x-datadome-params:servername = server.identity;
        set bereq.http.x-datadome-params:serverregion = server.region;
        set bereq.http.x-datadome-params:ip = urlencode(client.ip);
        set bereq.http.x-forwarded-proto = urlencode(req.protocol);
        set bereq.http.x-datadome-params:authorizationlen = std.strlen(req.http.authorization);
        # Truncating Headers - Start
        set bereq.http.accept-charset = substr(req.http.accept-charset, 0, 128);
        set bereq.http.accept-language = substr(req.http.accept-language, 0, 256);
        set bereq.http.x-requested-with = substr(req.http.x-requested-with, 0, 128);
        set bereq.http.x-fl-productid = substr(req.http.x-fl-productid, 0, 64);
        set bereq.http.x-flapi-session-id = substr(req.http.x-flapi-session-id, 0, 64);
        set bereq.http.fastly-orig-accept-encoding = substr(req.http.fastly-orig-accept-encoding, 0, 128);
        set bereq.http.cache-control = substr(req.http.cache-control, 0, 128);
        set bereq.http.connection = substr(req.http.connection, 0, 128);
        set bereq.http.pragma = substr(req.http.pragma, 0, 128);
        set bereq.http.accept = substr(req.http.accept, 0, 512);
        set bereq.http.host = substr(req.http.host, 0, 512);
        set bereq.http.origin = substr(req.http.origin, 0, 512);
        set bereq.http.server-hostname = substr(req.http.server-hostname, 0, 512);
        set bereq.http.server-name = substr(req.http.server-name, 0, 512);
        if( std.strlen(req.http.x-forwarded-for) > 512 ) {
            # Truncate from the end
            set bereq.http.x-forwarded-for = substr(req.http.x-forwarded-for, -512);
        } else {
            set bereq.http.x-forwarded-for = req.http.x-forwarded-for;
        }
        set bereq.http.user-agent = substr(req.http.user-agent, 0, 768);
        set bereq.http.referer = substr(req.http.referer, 0, 1024);
        set bereq.http.content-type = substr(req.http.content-type, 0, 64);
        set bereq.http.from = substr(req.http.from, 0, 128);
        set bereq.http.true-client-ip = substr(req.http.true-client-ip, 0, 128);
        set bereq.http.via = substr(req.http.via, 0, 256);
        set bereq.http.x-real-ip = substr(req.http.x-real-ip, 0, 128);
        set bereq.http.sec-ch-device-memory = substr(req.http.sec-ch-device-memory, 0, 8);
        set bereq.http.sec-ch-ua = substr(req.http.sec-ch-ua, 0, 128);
        set bereq.http.sec-ch-ua-arch = substr(req.http.sec-ch-ua-arch, 0, 16);
        set bereq.http.sec-ch-ua-full-version-list = substr(req.http.sec-ch-ua-full-version-list, 0, 256);
        set bereq.http.sec-ch-ua-mobile = substr(req.http.sec-ch-ua-mobile, 0, 8);
        set bereq.http.sec-ch-ua-model = substr(req.http.sec-ch-ua-model, 0, 128);
        set bereq.http.sec-ch-ua-platform = substr(req.http.sec-ch-ua-platform, 0, 32);
        set bereq.http.sec-fetch-dest = substr(req.http.sec-fetch-dest, 0, 32);
        set bereq.http.sec-fetch-mode = substr(req.http.sec-fetch-mode, 0, 32);
        set bereq.http.sec-fetch-site = substr(req.http.sec-fetch-site, 0, 64);
        set bereq.http.sec-fetch-user = substr(req.http.sec-fetch-user, 0, 8);
        set bereq.http.sec-fetch-storage-access = substr(req.http.sec-fetch-storage-access, 0, 8);
        set bereq.http.signature = substr(req.http.signature, 0, 512);
        set bereq.http.signature-agent = substr(req.http.signature-agent, 0, 512);
        set bereq.http.signature-input = substr(req.http.signature-input, 0, 2048);
        set bereq.http.skyfire-pay-id = substr(req.http.skyfire-pay-id, 0, 2048);
        set bereq.url = substr(req.url, 0, 2048);
        # Truncating Headers - End
        call handle_custom_fields;
        # unset empty custom fields to avoid sending them as empty values
        # truncate and encode customFields values
        if (std.strlen(bereq.http.x-datadome-params:customFieldString1) == 0 ) {
          unset bereq.http.x-datadome-params:customFieldString1;
        } else {
          set bereq.http.x-datadome-params:customFieldString1 = urlencode(substr(bereq.http.x-datadome-params:customFieldString1, 0, 256));
        }
        if (std.strlen(bereq.http.x-datadome-params:customFieldString2) == 0 ) {
          unset bereq.http.x-datadome-params:customFieldString2;
        } else {
          set bereq.http.x-datadome-params:customFieldString2 = urlencode(substr(bereq.http.x-datadome-params:customFieldString2, 0, 256));
        }
        if (std.strlen(bereq.http.x-datadome-params:customFieldString3) == 0 ) {
          unset bereq.http.x-datadome-params:customFieldString3;
        } else {
          set bereq.http.x-datadome-params:customFieldString3 = urlencode(substr(bereq.http.x-datadome-params:customFieldString3, 0, 256));
        }
        if (std.strlen(bereq.http.x-datadome-params:customFieldInteger1) == 0 ) {
          unset bereq.http.x-datadome-params:customFieldInteger1;
        } else {
          set bereq.http.x-datadome-params:customFieldInteger1 = urlencode(substr(bereq.http.x-datadome-params:customFieldInteger1, 0, 20));
        }
        if (std.strlen(bereq.http.x-datadome-params:customFieldInteger2) == 0 ) {
          unset bereq.http.x-datadome-params:customFieldInteger2;
        } else {
          set bereq.http.x-datadome-params:customFieldInteger2 = urlencode(substr(bereq.http.x-datadome-params:customFieldInteger2, 0, 20));
        }
        if (std.strlen(bereq.http.x-datadome-params:customFieldFloat1) == 0 ) {
          unset bereq.http.x-datadome-params:customFieldFloat1;
        } else {
          set bereq.http.x-datadome-params:customFieldFloat1 = urlencode(substr(bereq.http.x-datadome-params:customFieldFloat1, 0, 20));
        }
        if (std.strlen(bereq.http.x-datadome-params:userID) == 0 ) {
          unset bereq.http.x-datadome-params:userID;
        } else {
          set bereq.http.x-datadome-params:userID = urlencode(substr(bereq.http.x-datadome-params:userID, 0, 128));
        }
        if (std.strlen(bereq.http.x-datadome-params:productID) == 0 ) {
          unset bereq.http.x-datadome-params:productID;
        } else {
          set bereq.http.x-datadome-params:productID = urlencode(substr(bereq.http.x-datadome-params:productID, 0, 128));
        }

        if (req.http.x-datadome-clientid) {
            set bereq.http.x-datadome-params:clientid = urlencode(substr(req.http.x-datadome-clientid, 0, 512));
            set bereq.http.x-datadome-x-set-cookie = "true";
        } else {
            set bereq.http.x-datadome-params:clientid = urlencode(substr(req.http.cookie:datadome, 0, 512));
        }
        set bereq.http.x-datadome-params:cookieslen = std.strlen(req.http.cookie);
        # enforce gzip encoding between Fastly and DataDome
        set bereq.http.accept-encoding = "gzip";
        # disable ng-waf inspection on DataDome requests
        set bereq.http.x-sigsci-no-inspection = "true";
    } else {
        # prevent leak of the key
        unset bereq.http.x-datadome-params;
    }
  }
}

