      unset beresp.http.x-datadome-previousrequest-elapsed;
    }
  }
  unset beresp.http.x-datadome-headers;
  unset beresp.http.x-datadome-request-headers;
  # restore method
  if (req.http.x-datadome-params:method) {
    set req.method = urldecode(req.http.x-datadome-params:method);
  }
}

if (req.backend == datadome && req.http.x-datadome-params) {
  # the backend is set to 'DataDome' and
  # the presence of a header confirms it's an error during DataDome process
  restart;
}

# copy datadome headers if it isn't datadome request
if (fastly.ff.visits_this_service == 0 && req.backend != datadome) {
  declare local var.x-datadome-headers STRING;
  set var.x-datadome-headers = urldecode(req.http.x-datadome-headers-pairs:x-datadome-headers);
  if (var.x-datadome-headers ~ "(?i)(^| )+x-set-cookie( |$)+") {
    set resp.http.x-set-cookie = urldecode(req.http.x-datadome-headers-pairs:x-set-cookie);
