  {{#if logging_endpoint}}
  ## Debug DataDome
  log {"syslog "} req.service_id {" {{logging_endpoint}} :: "}
      " timestamp=%22" now
      "%22 client_ip=" req.http.Fastly-Client-IP
      " request=" req.method
      " url=%22" cstr_escape(req.url.path)
      "%22 restarts=" req.restarts
      " DataDomeDebug=" "Before_DataDome"
      " fastlyFF=" fastly.ff.visits_this_service;
  ##
  {{/if}}
declare local var.datadome_restore_referrer BOOL;
declare local var.datadome_enable_graphql_support BOOL;
declare local var.datadome_enable_replay_protection BOOL;
declare local var.datadome_enable_mcp_support BOOL;

set var.datadome_restore_referrer = {{datadome_restore_referrer}};
set var.datadome_enable_graphql_support = {{datadome_enable_graphql_support}};
set var.datadome_enable_replay_protection = {{datadome_enable_replay_protection}};
set var.datadome_enable_mcp_support = {{datadome_enable_mcp_support}};


if (fastly.ff.visits_this_service == 0 && req.restarts == 0) {
  unset req.http.x-datadome-params;
}
# Configure the regular expression below to match URLs that
# should be checked by DataDome
if (fastly.ff.visits_this_service == 0 && req.restarts == 0 && req.method != "FASTLYPURGE" && req.http.x-datadome-skip-detection != req.xid && !((req.method == "GET" || req.method == "HEAD") && req.url.path ~ "{{datadome_exclusion_ext}}")) {

  if (req.http.early-data == "1" && var.datadome_enable_replay_protection == true) {
    error 425;
  }

  set req.backend = datadome;
  unset req.http.x-datadome-params;
  set req.http.x-datadome-params:method = urlencode(req.method);
  set req.http.x-datadome-params:postparamlen = urlencode(req.http.content-length);
  set req.method = "GET";
  set req.http.x-datadome-params:tlsprotocol = urlencode(tls.client.protocol);
  set req.http.x-datadome-params:tlscipherslist = urlencode(tls.client.ciphers_list);
  set req.http.x-datadome-params:tlsextensionslist = urlencode(tls.client.tlsexts_list);
  set req.http.x-datadome-params:ja3 = urlencode(tls.client.ja3_md5);
  set req.http.x-datadome-params:ja4 = urlencode(tls.client.ja4);

  if (var.datadome_enable_graphql_support == true && req.http.x-datadome-params:method == "POST" && req.http.content-type ~ "(?i)application\/json" && req.url.path ~ "(?i)graphql") {
    declare local var.graphQLQuery STRING;
    set var.graphQLQuery = std.strstr(req.body, "%22query%22");
    if (var.graphQLQuery ~ "(?m)(query|mutation|subscription)?\s*([A-Za-z_][A-Za-z0-9_]*)?\s*[\({@]") {
      set req.http.x-datadome-params:graphqlOperationType = if(re.group.1, re.group.1, "query");
      if (re.group.2) {
        set req.http.x-datadome-params:graphqlOperationName = substr(re.group.2, 0, 128);
      }
    }
  }

  if (var.datadome_enable_mcp_support == true
    && req.url.path ~ "(?i)/mcp"
    && req.http.Accept ~ "(?i)text/event-stream"
    && (req.http.x-datadome-params:method == "GET" || req.http.x-datadome-params:method == "POST" || req.http.x-datadome-params:method == "DELETE")) {
      set req.http.x-datadome-params:mcpSessionId = urlencode(substr(req.http.mcp-session-id, 0, 64));
      set req.http.x-datadome-params:mcpProtocolVersion = urlencode(substr(req.http.mcp-protocol-version, 0, 16));
      if (req.http.x-datadome-params:method == "POST"
        && req.http.Accept ~ "(?i)application/json"
        && req.http.content-type ~ "(?i)application/json"
        && std.atoi(req.http.content-length) > 0
        && std.strlen(req.body) != 0) {
        declare local var.mcpData STRING;
        set var.mcpData = req.body;
        if (var.mcpData ~ {"(?s)\"jsonrpc\"\s*:\s*\"([^\"]+)\""}) {
          set req.http.x-datadome-params:jsonRpcVersion = urlencode(substr(re.group.1, 0, 8));
        }
        if (var.mcpData ~ {"(?s)\"id\"\s*:\s*(?:\"([^\"]+)\"|([0-9]+))"}) {
          # if it was a string, group 1 is set; if it was a number, group 2 is set
          if (re.group.1) {
            set req.http.x-datadome-params:jsonRpcRequestId = urlencode(substr(re.group.1, 0, 64));
          } elseif (re.group.2) {
            set req.http.x-datadome-params:jsonRpcRequestId = substr(re.group.2, 0, 64);
          }
        }
        if (var.mcpData ~ {"(?s)\"method\"\s*:\s*\"([^\"]+)\""}) {
          set req.http.x-datadome-params:mcpMethod = urlencode(substr(re.group.1, 0, 64));
        }
        if (req.http.x-datadome-params:mcpMethod == "initialize") {
          if (var.mcpData ~ {"(?s)\"params\"\s*:\s*\{.*?\"clientInfo\"\s*:\s*\{.*?\"name\"\s*:\s*\"([^\"]+)\""}) {
            set req.http.x-datadome-params:mcpParamsClientInfoName = urlencode(substr(re.group.1, 0, 64));
          }
          if (var.mcpData ~ {"(?s)\"params\"\s*:\s*\{.*?\"clientInfo\"\s*:\s*\{.*?\"version\"\s*:\s*\"([^\"]+)\""}) {
            set req.http.x-datadome-params:mcpParamsClientInfoVersion = urlencode(substr(re.group.1, 0, 16));
          }
        }
        if (req.http.x-datadome-params:mcpMethod == urlencode("tools/call")) {
          if (var.mcpData ~ {"(?s)\"params\"\s*:\s*\{.*?\"name\"\s*:\s*\"([^\"]+)\""}) {
            set req.http.x-datadome-params:mcpParamsToolName = urlencode(substr(re.group.1, 0, 64));
          }
        }
      }
  }

  if (var.datadome_restore_referrer == true && req.url ~ "dd_referrer=") {

    declare local var.decoded_url STRING;
    declare local var.complete_request_url STRING;
    set var.decoded_url = urldecode(req.url);
    set var.complete_request_url = req.protocol "://" req.http.host querystring.filter(var.decoded_url, "dd_referrer");

    if (urldecode(querystring.clean(req.http.referer)) == querystring.clean(var.complete_request_url)) {
        # Referer header is the same as the current URL

        if (std.strlen(querystring.get(req.url, "dd_referrer")) > 0) {
            # Not empty `dd_referrer`, restore header `referer` with param value
            set req.http.referer = urldecode(querystring.get(req.url, "dd_referrer"));
        } else if (querystring.get(req.url, "dd_referrer") == "") {
            # Empty `dd_referrer` param, remove header `referer`
            unset req.http.referer;
        } # Not set `dd_referrer`, do nothing

        # Remove `dd_referrer` query param from URL
        set req.url = querystring.filter(req.url, "dd_referrer");
    }
  }

  # Tidy any mention of dd_referrer in referer headers because the browser sees it
  if (var.datadome_restore_referrer == true && req.http.referer ~ "dd_referrer=") {
    set req.http.referer = querystring.filter(req.http.referer, "dd_referrer");
  }
  {{#if logging_endpoint}}
  ## Debug DataDome
  log {"syslog "} req.service_id {" {{logging_endpoint}} :: "}
      " timestamp=%22" now
      "%22 client_ip=" req.http.Fastly-Client-IP
      " request=" req.method
      " host=" req.http.host
      " url=%22" cstr_escape(req.url)
      "%22 request_referer=%22" cstr_escape(req.http.Referer)
      "%22 request_user_agent=%22" cstr_escape(req.http.User-Agent)
      "%22 request_accept_language=%22" cstr_escape(req.http.Accept-Language)
      "%22 request_accept_charset=%22" cstr_escape(req.http.Accept-Charset)
      "%22 contentLength=" req.http.Content-Length
      " restarts=" req.restarts
      " DataDomeDebug=" "To_DataDome"
      " fastlyFF=" fastly.ff.visits_this_service;
  ##
  {{/if}}
  return (pass);
} else {
  if (req.http.x-datadome-params:method) {
    set req.method = urldecode(req.http.x-datadome-params:method);
    # After a restart, clustering is disabled. This re-enables it.
    set req.http.fastly-force-shield = "1";
  }
  unset req.http.x-datadome-params;
  {{#if logging_endpoint}}
  ## Debug DataDome
  log {"syslog "} req.service_id {" {{logging_endpoint}} :: "}
      " timestamp=%22" now
      "%22 client_ip=" req.http.Fastly-Client-IP
      " request=" req.method
      " host=" req.http.host
      " url=%22" cstr_escape(req.url)
      "%22 request_referer=%22" cstr_escape(req.http.Referer)
      "%22 request_user_agent=%22" cstr_escape(req.http.User-Agent)
      "%22 request_accept_language=%22" cstr_escape(req.http.Accept-Language)
      "%22 request_accept_charset=%22" cstr_escape(req.http.Accept-Charset)
      "%22 contentLength=" req.http.Content-Length
      " restarts=" req.restarts
      " DataDomeDebug=" "Bypass_DataDome"
      " fastlyFF=" fastly.ff.visits_this_service;
  ##
  {{/if}}
}

unset req.http.x-datadome-skip-detection;

# we're using the first restart for datadome, update a part of fastly code
# we can't replace whole macros because we haven't got any idea about backends
if (req.restarts == 1) {
  if (!req.http.x-timer) {
    set req.http.x-timer = "S" time.start.sec "." time.start.usec_frac;
  }
  set req.http.x-timer = req.http.x-timer ",VS0";
